1073: 	// Remove empty custom objects from migrated singlestat panels (frontend filters them out)
1074: 	if custom, exists := defaults["custom"].(map[string]interface{}); exists {
1075: 		if len(custom) == 0 {
1076: 			// Check if this is a migrated singlestat panel by looking for characteristic properties
1077: 			isMigratedSinglestat := false
1078: 
1079: 			// Check for autoMigrateFrom property first
1080: 			if autoMigrateFrom, exists := panel["autoMigrateFrom"]; exists {
1081: 				if autoMigrateFrom == "singlestat" || autoMigrateFrom == "grafana-singlestat-panel" {
1082: 					isMigratedSinglestat = true
1083: 				}
1084: 			}
1085: 
1086: 			// If autoMigrateFrom is not present, check for characteristic migrated singlestat properties
1087: 			if !isMigratedSinglestat {
1088: 				// Check for color with fixedColor and mode "fixed" (from sparkline migration)
1089: 				if color, hasColor := defaults["color"].(map[string]interface{}); hasColor {
1090: 					if _, hasFixedColor := color["fixedColor"].(string); hasFixedColor {
1091: 						if mode, hasMode := color["mode"].(string); hasMode && mode == "fixed" {
1092: 							// Check for mappings array (from valueMaps migration)
1093: 							if _, hasMappings := defaults["mappings"].([]interface{}); hasMappings {
1094: 								isMigratedSinglestat = true
1095: 							}
1096: 						}
1097: 					}
1098: 				}
1099: 			}
1100: 
1101: 			// Only remove empty custom objects for migrated singlestat panels
1102: 			if isMigratedSinglestat {
1103: 				delete(defaults, "custom")
1104: 			}
1105: 		}
1106: 	}
